function typeWriter(element,texts,speed=100){let textIndex=0;let charIndex=0;let isDeleting=false;let currentText="";function type(){const fullText=texts[textIndex];if(isDeleting){currentText=fullText.substring(0,charIndex-1);charIndex--;}else{currentText=fullText.substring(0,charIndex+1);charIndex++;}element.textContent=currentText;let typeSpeed=isDeleting ? speed/2 : speed;if(!isDeleting&&charIndex===fullText.length){typeSpeed=2000;isDeleting=true;}else if(isDeleting&&charIndex===0){isDeleting=false;textIndex=(textIndex+1)% texts.length;typeSpeed=500;}setTimeout(type,typeSpeed);}type();}function createParticles(){const particlesContainer=document.querySelector(".particles");if(!particlesContainer)return;const particleCount=50;for(let i=0;i<particleCount;i++){const particle=document.createElement("div");particle.className="particle";particle.style.left=Math.random()*100+"%";particle.style.animationDelay=Math.random()*20+"s";particle.style.animationDuration=20+Math.random()*10+"s";particlesContainer.appendChild(particle);}}function handleScrollReveal(){const reveals=document.querySelectorAll(".scroll-reveal,.stagger-item");const contactCards=document.querySelectorAll(".contact-card.scroll-reveal");reveals.forEach((element,index)=>{const windowHeight=window.innerHeight;const elementTop=element.getBoundingClientRect().top;const elementVisible=150;if(elementTop<windowHeight-elementVisible){if(element.classList.contains("stagger-item")){setTimeout(()=>{element.classList.add("revealed");},index*100);}else{element.classList.add("revealed");}}});contactCards.forEach((card,index)=>{const windowHeight=window.innerHeight;const elementTop=card.getBoundingClientRect().top;const elementVisible=150;if(elementTop<windowHeight-elementVisible&&!card.classList.contains("revealed")){setTimeout(()=>{card.classList.add("revealed");},index*150);}});}function animateCounter(element,target,duration=2000){const start=0;const increment=target/(duration/16);let current=start;const updateCounter=()=>{current+=increment;if(current<target){element.textContent=Math.floor(current);requestAnimationFrame(updateCounter);}else{element.textContent=target;}};updateCounter();}function animateSkillBars(){const skillBars=document.querySelectorAll(".skill-progress");const observer=new IntersectionObserver((entries)=>{entries.forEach((entry)=>{if(entry.isIntersecting){const width=entry.target.getAttribute("data-width");entry.target.style.width=width+"%";observer.unobserve(entry.target);}});},{threshold: 0.5},);skillBars.forEach((bar)=>{observer.observe(bar);});}function initProjectSkills(){const projectCards=document.querySelectorAll(".project-skill-card");projectCards.forEach((card,index)=>{card.style.animationDelay=`${index*0.1}s`;const techItems=card.querySelectorAll(".project-tech-list li");techItems.forEach((item,i)=>{item.style.transitionDelay=`${i*0.05}s`;});});}function enhanceNavigation(){const navLinks=document.querySelectorAll(".nav-link");const hamburger=document.querySelector(".hamburger");const navMenu=document.querySelector(".nav-menu");navLinks.forEach((link)=>{link.addEventListener("click",(e)=>{const href=link.getAttribute("href");if(href.startsWith("#")){e.preventDefault();const target=document.querySelector(href);if(target){const offset=150;const targetPosition=target.offsetTop-offset;window.scrollTo({top: targetPosition,behavior: "smooth",});if(hamburger&&hamburger.classList.contains("active")){hamburger.classList.remove("active");navMenu.classList.remove("active");}}}});});if(hamburger){hamburger.addEventListener("click",()=>{hamburger.classList.toggle("active");navMenu.classList.toggle("active");});}}function enhanceCards(){const cards=document.querySelectorAll(".card,.project-skill-card");cards.forEach((card)=>{card.addEventListener("mouseenter",function(e){const rect=this.getBoundingClientRect();const x=e.clientX-rect.left;const y=e.clientY-rect.top;this.style.setProperty("--mouse-x",`${x}px`);this.style.setProperty("--mouse-y",`${y}px`);});});}function showLoader(){const loader=document.createElement("div");loader.className="loader";loader.innerHTML='<div class="spinner"></div>';document.body.appendChild(loader);window.addEventListener("load",()=>{setTimeout(()=>{loader.style.opacity="0";setTimeout(()=>{loader.remove();},300);},500);});}function enhanceTooltips(){const tooltipElements=document.querySelectorAll("[data-tooltip]");tooltipElements.forEach((element)=>{if(element.querySelector(".tooltip"))return;const tooltipText=element.getAttribute("data-tooltip");const tooltip=document.createElement("span");tooltip.className="tooltip";tooltip.textContent=tooltipText;const computedStyle=window.getComputedStyle(element);if(computedStyle.position==="static"){element.style.position="relative";}element.appendChild(tooltip);});}document.addEventListener("DOMContentLoaded",()=>{createParticles();const typewriterElement=document.querySelector(".typewriter");if(typewriterElement){const texts=["Data Scientist","Software Engineer","Lifelong Learner"];typewriterElement.textContent="";typeWriter(typewriterElement,texts,100);}enhanceNavigation();enhanceCards();initProjectSkills();handleScrollReveal();window.addEventListener("scroll",handleScrollReveal);animateSkillBars();const counters=document.querySelectorAll(".counter");counters.forEach((counter)=>{const target=parseInt(counter.getAttribute("data-target"));const observer=new IntersectionObserver((entries)=>{entries.forEach((entry)=>{if(entry.isIntersecting){animateCounter(counter,target);observer.unobserve(counter);}});});observer.observe(counter);});enhanceTooltips();const observer=new MutationObserver(()=>{enhanceTooltips();});observer.observe(document.body,{childList: true,subtree: true,});const mainContent=document.querySelector("main");if(mainContent){mainContent.style.opacity="0";mainContent.style.transition="opacity 0.5s ease";setTimeout(()=>{mainContent.style.opacity="1";},100);}});let scrollTimeout;window.addEventListener("scroll",()=>{if(scrollTimeout){window.cancelAnimationFrame(scrollTimeout);}scrollTimeout=window.requestAnimationFrame(()=>{handleScrollReveal();});});